import{createMovieCard}from './movieCard.js';export class Carousel{constructor(container,items,title,badgeText=''){this.container=typeof container==='string'?document.querySelector(container):container;this.items=items;this.title=title;this.badgeText=badgeText;this.viewport=null;this.prevBtn=null;this.nextBtn=null;if(this.container&&this.items&&this.items.length>0){this.render();}}render(){this.container.innerHTML='';this.container.className='carousel-section';const header=document.createElement('div');header.className='carousel-section__header';const titleGroup=document.createElement('div');titleGroup.className='carousel-section__title-group';titleGroup.innerHTML=`<h2 class="carousel-section__title">${this.title}</h2>${this.badgeText?`<span class="badge badge--red">${this.badgeText}</span>`:''}`;const nav=document.createElement('div');nav.className='carousel-section__nav';nav.innerHTML=`<button class="carousel-section__btn carousel-section__btn--prev" aria-label="Anterior" disabled>‹</button><button class="carousel-section__btn carousel-section__btn--next" aria-label="Siguiente">›</button>`;header.appendChild(titleGroup);header.appendChild(nav);const viewport=document.createElement('div');viewport.className='carousel-section__viewport';const track=document.createElement('div');track.className='carousel-section__track';this.items.forEach(item=>{const card=createMovieCard(item,{size:'md',showType:true,lazyLoad:true});const itemWrapper=document.createElement('div');itemWrapper.className='carousel-section__item';itemWrapper.appendChild(card);track.appendChild(itemWrapper);});viewport.appendChild(track);this.container.appendChild(header);this.container.appendChild(viewport);this.viewport=viewport;this.prevBtn=nav.querySelector('.carousel-section__btn--prev');this.nextBtn=nav.querySelector('.carousel-section__btn--next');this.setupNavigation();this.setupDragScroll();}setupNavigation(){const scrollAmount=()=>this.viewport.clientWidth*0.8;this.prevBtn.addEventListener('click',()=>{this.viewport.scrollBy({left:-scrollAmount(),behavior:'smooth'});});this.nextBtn.addEventListener('click',()=>{this.viewport.scrollBy({left:scrollAmount(),behavior:'smooth'});});const updateButtons=()=>{const scrollLeft=this.viewport.scrollLeft;const maxScrollLeft=this.viewport.scrollWidth-this.viewport.clientWidth;this.prevBtn.disabled=scrollLeft<=5;this.nextBtn.disabled=scrollLeft>=maxScrollLeft-5;};this.viewport.addEventListener('scroll',updateButtons);setTimeout(updateButtons,100);}setupDragScroll(){let isDown=false;let startX;let scrollLeft;let dragDistance=0;this.viewport.addEventListener('mousedown',(e)=>{if(e.button!==0)return;isDown=true;this.viewport.style.scrollBehavior='auto';startX=e.pageX-this.viewport.offsetLeft;scrollLeft=this.viewport.scrollLeft;dragDistance=0;});this.viewport.addEventListener('mouseleave',()=>{if(isDown){isDown=false;this.viewport.style.scrollBehavior='smooth';}});this.viewport.addEventListener('mouseup',()=>{if(isDown){isDown=false;this.viewport.style.scrollBehavior='smooth';}});this.viewport.addEventListener('mousemove',(e)=>{if(!isDown)return;e.preventDefault();const x=e.pageX-this.viewport.offsetLeft;const walk=(x-startX)*1.5;this.viewport.scrollLeft=scrollLeft-walk;dragDistance=Math.abs(walk);});this.viewport.addEventListener('click',(e)=>{if(dragDistance>10){e.preventDefault();e.stopPropagation();}},true);}}export default Carousel;